    })
  }

  if (!curl.toLowerCase().includes('content-type: application/json')) {
    curl += '-H "Content-Type: application/json" '
  }

  if (request.data) {
    curl += `-d '${JSON.stringify(request.data)}'`
  }
  return curl
}

